(265, 'WD Black SN850X SSD', 'WD Black SN850X SSD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'wd black sn850x ssd', 'wd black sn850x ssd ssd pcie gen4 nvme hiệu suất cao được thiết kế để chơi game cạnh tranh và khả năng phản hồi hệ thống cực nhanh. có tốc độ đọc lên đến 7300mb/s, tản nhiệt tùy chọn, chế độ tối ưu hóa chơi game, hỗ trợ phần mềm wd dashboard và quản lý nhiệt cao cấp cho khối lượng công việc tốc độ cao bền vững.'),
(266, 'Crucial P3 Plus NVMe SSD', 'Crucial P3 Plus SSD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'crucial p3 plus nvme ssd', 'crucial p3 plus nvme ssd ssd pcie gen4 nvme giá cả phải chăng mang đến hiệu suất mạnh mẽ hàng ngày để chơi game, năng suất văn phòng và nâng cấp máy trạm. có tốc độ đọc lên đến 5000mb/s, hệ số dạng m.2 2280, công nghệ micron advanced 3d nand, tiêu thụ điện năng thấp và tỷ lệ giá trên hiệu suất tuyệt vời.'),
(267, 'Kingston NV2 NVMe SSD', 'Kingston NV2 SSD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'kingston nv2 nvme ssd', 'kingston nv2 nvme ssd ssd pcie 4.0 nvme cấp thấp được sử dụng rộng rãi với thiết kế m.2 nhỏ gọn, hoạt động nhiệt hiệu quả, hiệu suất đáng tin cậy và tốc độ khởi động nhanh. thích hợp cho pc chơi game, máy tính xách tay và hệ thống văn phòng yêu cầu nâng cấp ssd giá cả phải chăng và cải thiện hiệu suất đa nhiệm.'),
(268, 'Samsung 870 EVO SATA SSD', 'Samsung 870 EVO SSD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'samsung 870 evo sata ssd', 'samsung 870 evo sata ssd một trong những ổ ssd sata đáng tin cậy nhất thế giới dành cho máy tính để bàn và máy tính xách tay. có giao diện sata iii, tốc độ đọc lên đến 560mb/giây, công nghệ bộ nhớ samsung v-nand, độ bền nâng cao, khả năng tương thích hệ thống rộng rãi và hiệu suất tính toán hàng ngày đáng tin cậy.'),
(269, 'Seagate BarraCuda HDD', 'Seagate BarraCuda HDD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'seagate barracuda hdd', 'seagate barracuda hdd ổ cứng máy tính để bàn phổ biến trên toàn cầu được thiết kế cho bộ nhớ lớn, thư viện trò chơi, tệp đa phương tiện và hệ thống văn phòng. có giao diện sata 6gb/s, tốc độ quay 7200rpm, dung lượng lưu trữ lớn và độ tin cậy lưu trữ lâu dài đáng tin cậy cho máy tính để bàn.'),
(270, 'WD Blue HDD', 'WD Blue HDD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'wd blue hdd', 'wd blue hdd ổ cứng chính đáng tin cậy được thiết kế cho máy tính để bàn hàng ngày, hệ thống văn phòng và môi trường lưu trữ gia đình. có giao diện sata iii, hoạt động ổn định, tiêu thụ điện năng thấp, khả năng tương thích rộng rãi với máy tính để bàn và hiệu suất lưu trữ lâu dài đáng tin cậy.'),
(271, 'Toshiba P300 HDD', 'Toshiba P300 HDD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'toshiba p300 hdd', 'toshiba p300 hdd ổ cứng máy tính để bàn dung lượng cao được thiết kế cho hệ thống chơi game, chỉnh sửa đa phương tiện và lưu trữ tệp chuyên nghiệp. có tốc độ quay 7200rpm, bộ nhớ đệm tích hợp lớn, giao diện sata và hiệu suất lưu trữ dung lượng cao ổn định cho người dùng khó tính.'),
(272, 'Seagate IronWolf NAS HDD', 'Seagate IronWolf HDD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'seagate ironwolf nas hdd', 'seagate ironwolf nas hdd ổ cứng được tối ưu hóa cho nas được xây dựng để hoạt động 24/7 trong các máy chủ gia đình và hệ thống nas doanh nghiệp. tính năng tối ưu hóa chương trình cơ sở agilearray, chống rung, khả năng tương thích raid, xếp hạng khối lượng công việc cao và hiệu suất đa ổ đĩa đáng tin cậy cho các hệ thống lưu trữ chuyên nghiệp.'),
(273, 'WD Purple Surveillance HDD', 'WD Purple HDD.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'wd purple surveillance hdd', 'wd purple surveillance hdd ổ cứng giám sát chuyên dụng được thiết kế cho camera quan sát và hệ thống ghi âm an ninh. có công nghệ allframe, quay video liên tục được tối ưu hóa, độ bền nâng cao để hoạt động 24/7 và khả năng tương thích với hệ thống giám sát dvr và nvr.'),
(274, 'ASUS ROG Maximus Z790 Hero', 'ASUS ROG Maximus Z790 Hero.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rog maximus z790 hero', 'asus rog maximus z790 hero bo mạch chủ chơi game cao cấp cao cấp được thiết kế cho các hệ thống đam mê intel. có chipset intel z790, ổ cắm lga1700, hỗ trợ bộ nhớ ddr5 lên đến 192gb, mở rộng pcie 5.0, wi-fi 6e, nhiều khe cắm m.2 nvme, tản nhiệt vrm cao cấp, đèn rgb, kết nối thunderbolt và khả năng ép xung nâng cao. được công nhận rộng rãi trong giới game thủ, streamer và nhà lắp ráp pc chuyên nghiệp trên toàn thế giới.'),
(275, 'GIGABYTE Z790 AORUS Elite AX', 'GIGABYTE Z790 AORUS Elite AX.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'gigabyte z790 aorus elite ax', 'gigabyte z790 aorus elite ax bo mạch chủ chơi game intel phổ biến có chipset z790, ổ cắm lga1700, hỗ trợ ddr5, pcie 5.0, wi-fi 6e, ethernet 2.5gb, nhiều khe cắm ssd m.2, thiết kế tản nhiệt vrm tiên tiến và tối ưu hóa bios tập trung vào chơi game. rất khuyến khích cho các bản dựng máy trạm và chơi game hiệu suất cao.'),
(276, 'MSI MAG X870 TOMAHAWK WIFI', 'MSI MAG X870 TOMAHAWK WIFI.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'msi mag x870 tomahawk wifi', 'msi mag x870 tomahawk wifi bo mạch chủ chơi game amd am5 hiện đại được thiết kế cho bộ vi xử lý ryzen. có chipset amd x870, hỗ trợ ddr5, pcie 5.0, wi-fi 7, bluetooth 5.4, khe cắm pcie được gia cố, tản nhiệt tiên tiến và kết nối usb tốc độ cao. tuyệt vời cho hệ thống người sáng tạo và chơi game thế hệ tiếp theo.'),
(277, 'ASUS TUF Gaming B650-PLUS WIFI', 'ASUS TUF Gaming B650-PLUS WIFI.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus tuf gaming b650plus wifi', 'asus tuf gaming b650plus wifi bo mạch chủ amd am5 bền bỉ được thiết kế để chơi game phổ thông và độ tin cậy lâu dài. có chipset b650, hỗ trợ bộ nhớ ddr5, hỗ trợ pcie 5.0 m.2, các thành phần cấp quân sự, wi-fi 6, giải pháp làm mát toàn diện và khe cắm pcie được gia cố. phổ biến đối với các game thủ tìm kiếm độ tin cậy và giá trị.'),
(278, 'MSI B650 Gaming Plus WIFI', 'MSI B650 Gaming Plus WIFI.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'msi b650 gaming plus wifi', 'msi b650 gaming plus wifi bo mạch chủ amd tầm trung có socket am5, hỗ trợ bộ nhớ ddr5, tương thích pcie 4.0/5.0, hỗ trợ wi-fi, thiết kế tản nhiệt mở rộng, kết nối usb tốc độ cao và hiệu suất tản nhiệt hướng đến chơi game. được sử dụng rộng rãi trong các bản dựng pc chơi game ryzen trên toàn thế giới.'),
(279, 'ASRock B650M-HDV/M.2', 'ASRock B650M-HDV M2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asrock b650mhdvm2', 'asrock b650mhdvm2 bo mạch chủ amd am5 micro-atx giá cả phải chăng và đáng tin cậy được thiết kế cho máy tính văn phòng và chơi game giá rẻ. có hỗ trợ ddr5, bộ nhớ pcie 4.0 m.2, hệ thống cung cấp năng lượng bền bỉ, đầu ra hdmi/displayport và thiết kế micro-atx nhỏ gọn phù hợp với các bản dựng nhỏ hơn.'),
(280, 'GIGABYTE X870E AORUS MASTER', 'GIGABYTE X870E AORUS MASTER.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'gigabyte x870e aorus master', 'gigabyte x870e aorus master bo mạch chủ amd đẳng cấp dành cho người đam mê có chipset x870e, socket am5, hỗ trợ gpu pcie 5.0 và ssd, kiến trúc vrm cao cấp, wi-fi 7, mạng tốc độ cao, hệ thống tản nhiệt tiên tiến và nhiều khe cắm lưu trữ nvme. được thiết kế để chơi game cực đỉnh và hiệu suất máy trạm chuyên nghiệp.'),
(281, 'ASUS PRIME H610M-K D4', 'ASUS PRIME H610M-K D4.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus prime h610mk d4', 'asus prime h610mk d4 bo mạch chủ intel cấp thấp được thiết kế cho pc văn phòng và hệ thống máy tính để bàn giá cả phải chăng. có chipset intel h610, ổ cắm lga1700, hỗ trợ bộ nhớ ddr4, khả năng tương thích pcie 4.0, hỗ trợ m.2 nvme và hiệu suất tính toán ổn định hàng ngày. thường được sử dụng trong pc doanh nghiệp và văn phòng tại nhà.'),
(282, 'MSI PRO B760M-A WIFI', 'MSI PRO B760M-A WIFI.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'msi pro b760ma wifi', 'msi pro b760ma wifi bo mạch chủ intel tập trung vào doanh nghiệp và năng suất hỗ trợ bộ xử lý intel thế hệ thứ 12/13/14. có hỗ trợ bộ nhớ ddr5, pcie 4.0, kết nối wi-fi, thiết kế tản nhiệt cấp độ chuyên nghiệp, hỗ trợ ssd m.2 và cung cấp năng lượng ổn định cho khối lượng công việc văn phòng và người sáng tạo.'),
(283, 'ASUS ROG Strix B550-F Gaming WIFI II', 'ASUS ROG Strix B550-F Gaming WIFI II.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rog strix b550f gaming wifi ii', 'asus rog strix b550f gaming wifi ii một trong những bo mạch chủ chơi game amd am4 phổ biến nhất thế giới. có chipset amd b550, hỗ trợ pcie 4.0, khả năng tương thích bộ nhớ ddr4, wi-fi 6, âm thanh supremefx cao cấp, khe cắm pcie được gia cố, ánh sáng rgb và tản nhiệt vrm mạnh mẽ cho các hệ thống chơi game và phát trực tuyến.'),
(284, 'Intel Core i9-14900K', 'Intel Core i9-14900K.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'intel core i914900k', 'intel core i914900k bộ xử lý máy tính để bàn hàng đầu của intel được thiết kế cho những người đam mê chơi game, phát trực tuyến và khối lượng công việc của người sáng tạo chuyên nghiệp. có 24 lõi (8 hiệu suất + 16 lõi hiệu quả), 32 luồng, xung nhịp tăng lên đến 6.0ghz, khả năng tương thích với ổ cắm intel lga1700, hỗ trợ bộ nhớ ddr5/ddr4, hỗ trợ pcie 5.0, intel uhd graphics 770 tích hợp, khả năng ép xung được mở khóa và kiến trúc lai tiên tiến cho hiệu suất chơi game và đa nhiệm cực cao.'),
(285, 'Intel Core i7-14700K', 'Intel Core i7-14700K.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'intel core i714700k', 'intel core i714700k bộ xử lý năng suất và chơi game hiệu suất cao với 20 lõi (8p + 12e), 28 luồng, tốc độ tăng lên đến 5,6ghz, kiến trúc lai intel, khả năng tương thích ddr5/ddr4, hỗ trợ pcie 5.0, đồ họa tích hợp và hệ số nhân mở khóa để ép xung. được sử dụng rộng rãi trong pc chơi game và hệ thống máy trạm trên toàn cầu.');

