--- product_translations ---
(265, 265, 'vi', 'WD Black SN850X SSD', '', '<p>SSD PCIe Gen4 NVMe hiệu suất cao được thiết kế để chơi game cạnh tranh và khả năng phản hồi hệ thống cực nhanh. Có tốc độ đọc lên đến 7300MB/s, tản nhiệt tùy chọn, chế độ tối ưu hóa chơi game, hỗ trợ phần mềm WD Dashboard và quản lý nhiệt cao cấp cho khối lượng công việc tốc độ cao bền vững.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(266, 266, 'vi', 'Crucial P3 Plus NVMe SSD', '', '<p>SSD PCIe Gen4 NVMe giá cả phải chăng mang đến hiệu suất mạnh mẽ hàng ngày để chơi game, năng suất văn phòng và nâng cấp máy trạm. Có tốc độ đọc lên đến 5000MB/s, hệ số dạng M.2 2280, công nghệ Micron Advanced 3D NAND, tiêu thụ điện năng thấp và tỷ lệ giá trên hiệu suất tuyệt vời.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(267, 267, 'vi', 'Kingston NV2 NVMe SSD', '', '<p>SSD PCIe 4.0 NVMe cấp thấp được sử dụng rộng rãi với thiết kế M.2 nhỏ gọn, hoạt động nhiệt hiệu quả, hiệu suất đáng tin cậy và tốc độ khởi động nhanh. Thích hợp cho PC chơi game, máy tính xách tay và hệ thống văn phòng yêu cầu nâng cấp SSD giá cả phải chăng và cải thiện hiệu suất đa nhiệm.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(268, 268, 'vi', 'Samsung 870 EVO SATA SSD', '', '<p>Một trong những ổ SSD SATA đáng tin cậy nhất thế giới dành cho máy tính để bàn và máy tính xách tay. Có giao diện SATA III, tốc độ đọc lên đến 560MB/giây, công nghệ bộ nhớ Samsung V-NAND, độ bền nâng cao, khả năng tương thích hệ thống rộng rãi và hiệu suất tính toán hàng ngày đáng tin cậy.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(269, 269, 'vi', 'Seagate BarraCuda HDD', '', '<p>Ổ cứng máy tính để bàn phổ biến trên toàn cầu được thiết kế cho bộ nhớ lớn, thư viện trò chơi, tệp đa phương tiện và hệ thống văn phòng. Có giao diện SATA 6Gb/s, tốc độ quay 7200RPM, dung lượng lưu trữ lớn và độ tin cậy lưu trữ lâu dài đáng tin cậy cho máy tính để bàn.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(270, 270, 'vi', 'WD Blue HDD', '', '<p>Ổ cứng chính đáng tin cậy được thiết kế cho máy tính để bàn hàng ngày, hệ thống văn phòng và môi trường lưu trữ gia đình. Có giao diện SATA III, hoạt động ổn định, tiêu thụ điện năng thấp, khả năng tương thích rộng rãi với máy tính để bàn và hiệu suất lưu trữ lâu dài đáng tin cậy.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(271, 271, 'vi', 'Toshiba P300 HDD', '', '<p>Ổ cứng máy tính để bàn dung lượng cao được thiết kế cho hệ thống chơi game, chỉnh sửa đa phương tiện và lưu trữ tệp chuyên nghiệp. Có tốc độ quay 7200RPM, bộ nhớ đệm tích hợp lớn, giao diện SATA và hiệu suất lưu trữ dung lượng cao ổn định cho người dùng khó tính.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(272, 272, 'vi', 'Seagate IronWolf NAS HDD', '', '<p>Ổ cứng được tối ưu hóa cho NAS được xây dựng để hoạt động 24/7 trong các máy chủ gia đình và hệ thống NAS doanh nghiệp. Tính năng tối ưu hóa chương trình cơ sở AgileArray, chống rung, khả năng tương thích RAID, xếp hạng khối lượng công việc cao và hiệu suất đa ổ đĩa đáng tin cậy cho các hệ thống lưu trữ chuyên nghiệp.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(273, 273, 'vi', 'WD Purple Surveillance HDD', '', '<p>Ổ cứng giám sát chuyên dụng được thiết kế cho camera quan sát và hệ thống ghi âm an ninh. Có công nghệ AllFrame, quay video liên tục được tối ưu hóa, độ bền nâng cao để hoạt động 24/7 và khả năng tương thích với hệ thống giám sát DVR và NVR.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(274, 274, 'vi', 'ASUS ROG Maximus Z790 Hero', '', '<p>Bo mạch chủ chơi game cao cấp cao cấp được thiết kế cho các hệ thống đam mê Intel. Có chipset Intel Z790, ổ cắm LGA1700, hỗ trợ bộ nhớ DDR5 lên đến 192GB, mở rộng PCIe 5.0, Wi-Fi 6E, nhiều khe cắm M.2 NVMe, tản nhiệt VRM cao cấp, đèn RGB, kết nối Thunderbolt và khả năng ép xung nâng cao. Được công nhận rộng rãi trong giới game thủ, streamer và nhà lắp ráp PC chuyên nghiệp trên toàn thế giới.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(275, 275, 'vi', 'GIGABYTE Z790 AORUS Elite AX', '', '<p>Bo mạch chủ chơi game Intel phổ biến có chipset Z790, ổ cắm LGA1700, hỗ trợ DDR5, PCIe 5.0, Wi-Fi 6E, Ethernet 2.5Gb, nhiều khe cắm SSD M.2, thiết kế tản nhiệt VRM tiên tiến và tối ưu hóa BIOS tập trung vào chơi game. Rất khuyến khích cho các bản dựng máy trạm và chơi game hiệu suất cao.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(276, 276, 'vi', 'MSI MAG X870 TOMAHAWK WIFI', '', '<p>Bo mạch chủ chơi game AMD AM5 hiện đại được thiết kế cho bộ vi xử lý Ryzen. Có chipset AMD X870, hỗ trợ DDR5, PCIe 5.0, Wi-Fi 7, Bluetooth 5.4, khe cắm PCIe được gia cố, tản nhiệt tiên tiến và kết nối USB tốc độ cao. Tuyệt vời cho hệ thống người sáng tạo và chơi game thế hệ tiếp theo.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(277, 277, 'vi', 'ASUS TUF Gaming B650-PLUS WIFI', '', '<p>Bo mạch chủ AMD AM5 bền bỉ được thiết kế để chơi game phổ thông và độ tin cậy lâu dài. Có chipset B650, hỗ trợ bộ nhớ DDR5, hỗ trợ PCIe 5.0 M.2, các thành phần cấp quân sự, Wi-Fi 6, giải pháp làm mát toàn diện và khe cắm PCIe được gia cố. Phổ biến đối với các game thủ tìm kiếm độ tin cậy và giá trị.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(278, 278, 'vi', 'MSI B650 Gaming Plus WIFI', '', '<p>Bo mạch chủ AMD tầm trung có socket AM5, hỗ trợ bộ nhớ DDR5, tương thích PCIe 4.0/5.0, hỗ trợ Wi-Fi, thiết kế tản nhiệt mở rộng, kết nối USB tốc độ cao và hiệu suất tản nhiệt hướng đến chơi game. Được sử dụng rộng rãi trong các bản dựng PC chơi game Ryzen trên toàn thế giới.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(279, 279, 'vi', 'ASRock B650M-HDV/M.2', '', '<p>Bo mạch chủ AMD AM5 micro-ATX giá cả phải chăng và đáng tin cậy được thiết kế cho máy tính văn phòng và chơi game giá rẻ. Có hỗ trợ DDR5, bộ nhớ PCIe 4.0 M.2, hệ thống cung cấp năng lượng bền bỉ, đầu ra HDMI/DisplayPort và thiết kế micro-ATX nhỏ gọn phù hợp với các bản dựng nhỏ hơn.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(280, 280, 'vi', 'GIGABYTE X870E AORUS MASTER', '', '<p>Bo mạch chủ AMD đẳng cấp dành cho người đam mê có chipset X870E, socket AM5, hỗ trợ GPU PCIe 5.0 và SSD, kiến trúc VRM cao cấp, Wi-Fi 7, mạng tốc độ cao, hệ thống tản nhiệt tiên tiến và nhiều khe cắm lưu trữ NVMe. Được thiết kế để chơi game cực đỉnh và hiệu suất máy trạm chuyên nghiệp.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(281, 281, 'vi', 'ASUS PRIME H610M-K D4', '', '<p>Bo mạch chủ Intel cấp thấp được thiết kế cho PC văn phòng và hệ thống máy tính để bàn giá cả phải chăng. Có chipset Intel H610, ổ cắm LGA1700, hỗ trợ bộ nhớ DDR4, khả năng tương thích PCIe 4.0, hỗ trợ M.2 NVMe và hiệu suất tính toán ổn định hàng ngày. Thường được sử dụng trong PC doanh nghiệp và văn phòng tại nhà.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(282, 282, 'vi', 'MSI PRO B760M-A WIFI', '', '<p>Bo mạch chủ Intel tập trung vào doanh nghiệp và năng suất hỗ trợ bộ xử lý Intel thế hệ thứ 12/13/14. Có hỗ trợ bộ nhớ DDR5, PCIe 4.0, kết nối Wi-Fi, thiết kế tản nhiệt cấp độ chuyên nghiệp, hỗ trợ SSD M.2 và cung cấp năng lượng ổn định cho khối lượng công việc văn phòng và người sáng tạo.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(283, 283, 'vi', 'ASUS ROG Strix B550-F Gaming WIFI II', '', '<p>Một trong những bo mạch chủ chơi game AMD AM4 phổ biến nhất thế giới. Có chipset AMD B550, hỗ trợ PCIe 4.0, khả năng tương thích bộ nhớ DDR4, Wi-Fi 6, âm thanh SupremeFX cao cấp, khe cắm PCIe được gia cố, ánh sáng RGB và tản nhiệt VRM mạnh mẽ cho các hệ thống chơi game và phát trực tuyến.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(284, 284, 'vi', 'Intel Core i9-14900K', '', '<p>Bộ xử lý máy tính để bàn hàng đầu của Intel được thiết kế cho những người đam mê chơi game, phát trực tuyến và khối lượng công việc của người sáng tạo chuyên nghiệp. Có 24 lõi (8 Hiệu suất + 16 lõi hiệu quả), 32 luồng, xung nhịp tăng lên đến 6.0GHz, khả năng tương thích với ổ cắm Intel LGA1700, hỗ trợ bộ nhớ DDR5/DDR4, hỗ trợ PCIe 5.0, Intel UHD Graphics 770 tích hợp, khả năng ép xung được mở khóa và kiến trúc lai tiên tiến cho hiệu suất chơi game và đa nhiệm cực cao.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00'),
(285, 285, 'vi', 'Intel Core i7-14700K', '', '<p>Bộ xử lý năng suất và chơi game hiệu suất cao với 20 lõi (8P + 12E), 28 luồng, tốc độ tăng lên đến 5,6GHz, kiến trúc lai Intel, khả năng tương thích DDR5/DDR4, hỗ trợ PCIe 5.0, đồ họa tích hợp và hệ số nhân mở khóa để ép xung. Được sử dụng rộng rãi trong PC chơi game và hệ thống máy trạm trên toàn cầu.</p>', '2024-05-14 04:20:00', '2024-05-14 04:20:00');

